function EditBtn() {
  const navigate = useNavigate();
  const location = useLocation();
  const playlistId = location.pathname.split("/")[2];

  return (
    <motion.button
      className="edit-btn"
      whileTap={{ scale: 0.9 }}
      onClick={() => navigate(`/edit-playlist/${playlistId}`)}
    >
      <svg
        width="24"
        height="24"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="2"
        strokeLinecap="round"
        strokeLinejoin="round"
      >
        <path d="M11 4H4a2 2 0 0 0-2 2v14a2 2 0 0 0 2 2h14a2 2 0 0 0 2-2v-7"></path>
        <path d="M18.5 2.5a2.121 2.121 0 0 1 3 3L12 15l-4 1 1-4 9.5-9.5z"></path>
      </svg>
    </motion.button>
  );
}

function Header() {
  const location = useLocation();
  const path = location.pathname.toLowerCase();

  const isBackPage =
    path.includes("now-playing") ||
    path.includes("see-all") ||
    path.includes("settings") ||
    path.includes("download") ||
    path.includes("playlist") ||
    path.includes("artist") ||
    path.includes("create-playlist");

  const isPlaylistDetail =
    path.includes("playlist/") && !path.includes("edit-playlist");

  return (
    <div className="Header">
      {isBackPage ? <BackBtn /> : <SettingsBtn />}
      {/* {isPlaylistDetail && <EditBtn />} */}
    </div>
  );
}

export default Header;
